const fs = require('fs');
const content = fs.readFileSync('/Users/javi/projects/trackgentic/.agentic/expertise/library-quality/library-quality-index.yaml', 'utf8');
// Basic YAML validation - check for common issues
const lines = content.split('\n');
let errors = 0;
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  // Check for tab characters
  if (line.includes('\t')) {
    console.log('Tab found at line ' + (i+1));
    errors++;
  }
}
if (errors === 0) console.log('No obvious YAML issues found. ' + lines.length + ' lines.');
